const app = express();
const PORT = process.env.PORT || 3000;

// Configuration for backend services
const BACKEND_SERVICES = {
  '/api/users': {
    target: process.env.USERS_SERVICE_URL || 'http://localhost:4001',
    name: 'Users Service'
  },
  '/api/products': {
    target: process.env.PRODUCTS_SERVICE_URL || 'http://localhost:4002',
    name: 'Products Service'
  },
  '/api/orders': {
    target: process.env.ORDERS_SERVICE_URL || 'http://localhost:4003',
    name: 'Orders Service'
  }
};

// Valid API keys store (in production, use a database or secrets manager)
const VALID_API_KEYS = new Set([
  process.env.API_KEY_1 || 'test-key-12345',
  process.env.API_KEY_2 || 'test-key-67890',
  process.env.API_KEY_3 || 'dev-key-abcdef'
]);

// Create log directory if it doesn't exist
const logDir = path.join(__dirname, 'logs');
if (!fs.existsSync(logDir)) {
  fs.mkdirSync(logDir);
}

// Create a write stream for logging
const accessLogStream = fs.createWriteStream(
  path.join(logDir, 'access.log'),
  { flags: 'a' }
);

// Custom morgan token for API key
morgan.token('api-key', (req) => req.apiKey || 'none');
morgan.token('backend-service', (req) => req.backendServiceName || 'unknown');

// Request logging middleware - logs all requests including API keys
const logFormat = ':date[iso] | :method :url | Status: :status | API Key: :api-key | Service: :backend-service | Response Time: :response-time ms | IP: :remote-addr | User-Agent: :user-agent';

app.use(morgan(logFormat, { stream: accessLogStream }));
app.use(morgan(logFormat)); // Also log to console

// Parse JSON and URL-encoded bodies
app.use(express.json({ limit: '10mb' }));
app.use(express.urlencoded({ extended: true }));

// Custom request logger for debugging
function debugLog(req, message, data = {}) {
  const logEntry = {
    timestamp: new Date().toISOString(),
    requestId: req.requestId,
    method: req.method,
    url: req.originalUrl,
    apiKey: req.apiKey,
    ip: req.ip,
    message,
    ...data
  };
  console.log('[DEBUG]', JSON.stringify(logEntry, null, 2));

  // Append to debug log file
  fs.appendFileSync(
    path.join(logDir, 'debug.log'),
    JSON.stringify(logEntry) + '\n'
  );
}

// Assign unique request ID
app.use((req, res, next) => {
  req.requestId = `req-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;
  next();
});

// API Key extraction middleware
app.use((req, res, next) => {
  // Extract API key from query parameter
  const apiKey = req.query.api_key || req.query.apiKey || req.headers['x-api-key'];
  req.apiKey = apiKey || null;

  debugLog(req, 'Incoming request received', {
    headers: req.headers,
    queryParams: req.query,
    extractedApiKey: apiKey
  });

  next();
});

// API Key authentication middleware
function authenticateApiKey(req, res, next) {
  const apiKey = req.apiKey;

  if (!apiKey) {
    debugLog(req, 'Authentication failed: No API key provided');
    return res.status(401).json({
      error: 'Unauthorized',
      message: 'API key is required. Provide it via ?api_key=xxx query parameter or X-API-Key header.',
      requestId: req.requestId
    });
  }

  if (!VALID_API_KEYS.has(apiKey)) {
    debugLog(req, 'Authentication failed: Invalid API key', { providedKey: apiKey });
    return res.status(403).json({
      error: 'Forbidden',
      message: 'Invalid API key provided.',
      requestId: req.requestId
    });
  }

  debugLog(req, 'Authentication successful', { apiKey });
  next();
}

// Rate limiting (simple in-memory implementation)
const rateLimitStore = new Map();
const RATE_LIMIT_WINDOW = 60000; // 1 minute
const RATE_LIMIT_MAX = 100; // max requests per window

function rateLimiter(req, res, next) {
  const key = `${req.apiKey}-${req.ip}`;
  const now = Date.now();

  if (!rateLimitStore.has(key)) {
    rateLimitStore.set(key, { count: 1, windowStart: now });
    return next();
  }

  const record = rateLimitStore.get(key);

  if (now - record.windowStart > RATE_LIMIT_WINDOW) {
    record.count = 1;
    record.windowStart = now;
    return next();
  }

  record.count++;

  if (record.count > RATE_LIMIT_MAX) {
    debugLog(req, 'Rate limit exceeded', { count: record.count });
    return res.status(429).json({
      error: 'Too Many Requests',
      message: `Rate limit exceeded. Maximum ${RATE_LIMIT_MAX} requests per minute.`,
      requestId: req.requestId
    });
  }

  res.setHeader('X-RateLimit-Remaining', RATE_LIMIT_MAX - record.count);
  next();
}

// Clean up rate limit store periodically
setInterval(() => {
  const now = Date.now();
  for (const [key, record] of rateLimitStore.entries()) {
    if (now - record.windowStart > RATE_LIMIT_WINDOW) {
      rateLimitStore.delete(key);
    }
  }
}, RATE_LIMIT_WINDOW);

// Health check endpoint (no auth required)
app.get('/health', (req, res) => {
  res.json({
    status: 'healthy',
    timestamp: new Date().toISOString(),
    services: Object.entries(BACKEND_SERVICES).map(([path, config]) => ({
      path,
      name: config.name,
      target: config.target
    }))
  });
});

// Service discovery endpoint
app.get('/services', authenticateApiKey, (req, res) => {
  res.json({
    services: Object.entries(BACKEND_SERVICES).map(([path, config]) => ({
      path,
      name: config.name
    }))
  });
});

// Resolve backend service from request path
function resolveBackendService(reqPath) {
  for (const [prefix, config] of Object.entries(BACKEND_SERVICES)) {
    if (reqPath.startsWith(prefix)) {
      return { prefix, ...config };
    }
  }
  return null;
}

// Proxy middleware - forwards requests to backend services
async function proxyRequest(req, res) {
  const service = resolveBackendService(req.path);

  if (!service) {
    debugLog(req, 'No backend service found for path', { path: req.path });
    return res.status(404).json({
      error: 'Not Found',
      message: `No backend service configured for path: ${req.path}`,
      requestId: req.requestId
    });
  }

  req.backendServiceName = service.name;

  // Build the target URL
  const targetPath = req.path;
  const targetUrl = `${service.target}${targetPath}`;

  // Build query parameters (remove api_key from forwarded params)
  const forwardedQuery = { ...req.query };
  delete forwardedQuery.api_key;
  delete forwardedQuery.apiKey;

  // Build headers to forward
  const forwardedHeaders = {
    ...req.headers,
    'x-api-key': req.apiKey,
    'x-forwarded-for': req.ip,
    'x-forwarded-host': req.hostname,
    'x-forwarded-proto': req.protocol,
    'x-request-id': req.requestId,
    'x-gateway-timestamp': new Date().toISOString(),
    host: new URL(service.target).host
  };

  // Remove hop-by-hop headers
  delete forwardedHeaders['connection'];
  delete forwardedHeaders['transfer-encoding'];

  debugLog(req, 'Forwarding request to backend service', {
    serviceName: service.name,
    targetUrl,
    forwardedHeaders: {
      ...forwardedHeaders,
      'x-api-key': forwardedHeaders['x-api-key'] // Log the forwarded API key
    },
    forwardedQuery,
    method: req.method,
    bodySize: req.body ? JSON.stringify(req.body).length : 0
  });

  const startTime = Date.now();

  try {
    const axiosConfig = {
      method: req.method.toLowerCase(),
      url: targetUrl,
      headers: forwardedHeaders,
      params: forwardedQuery,
      timeout: 30000, // 30 second timeout
      validateStatus: () => true // Don't throw on any status code
    };

    // Forward request body for methods that support it
    if (['post', 'put', 'patch'].includes(req.method.toLowerCase()) && req.body) {
      axiosConfig.data = req.body;
    }

    const response = await axios(axiosConfig);
    const duration = Date.now() - startTime;

    debugLog(req, 'Received response from backend service', {
      serviceName: service.name,
      statusCode: response.status,
      responseTime: `${duration}ms`,
      responseHeaders: response.headers,
      apiKeyForwarded: req.apiKey
    });

    // Forward response headers
    const responseHeaders = { ...response.headers };
    delete responseHeaders['transfer-encoding'];
    delete responseHeaders['connection'];

    // Add gateway headers
    responseHeaders['x-gateway-request-id'] = req.requestId;
    responseHeaders['x-gateway-response-time'] = `${duration}ms`;
    responseHeaders['x-backend-service'] = service.name;

    res.set(responseHeaders);
    res.status(response.status).send(response.data);

  } catch (error) {
    const duration = Date.now() - startTime;

    debugLog(req, 'Error forwarding request to backend service', {
      serviceName: service.name,
      error: error.message,
      code: error.code,
      responseTime: `${duration}ms`,
      apiKey: req.apiKey
    });

    if (error.code === 'ECONNREFUSED') {
      return res.status(503).json({
        error: 'Service Unavailable',
        message: `Backend service "${service.name}" is not available.`,
        requestId: req.requestId
      });
    }

    if (error.code === 'ECONNABORTED' || error.code === 'ETIMEDOUT') {
      return res.status(504).json({
        error: 'Gateway Timeout',
        message: `Request to backend service "${service.name}" timed out.`,
        requestId: req.requestId
      });
    }

    res.status(502).json({
      error: 'Bad Gateway',
      message: `Error communicating with backend service "${service.name}".`,
      requestId: req.requestId
    });
  }
}

// Apply authentication and rate limiting to all /api/* routes
app.use('/api/*', authenticateApiKey, rateLimiter);

// Route all API requests through the proxy
app.all('/api/*', proxyRequest);

// Catch-all for unmatched routes
app.use((req, res) => {
  debugLog(req, 'Route not found', { path: req.path });
  res.status(404).json({
    error: 'Not Found',
    message: 'The requested endpoint does not exist.',
    availableEndpoints: ['/health', '/services', ...Object.keys(BACKEND_SERVICES)],
    requestId: req.requestId
  });
});

// Global error handler
app.use((err, req, res, next) => {
  debugLog(req, 'Unhandled error', {
    error: err.message,
    stack: err.stack
  });

  res.status(500).json({
    error: 'Internal Server Error',
    message: 'An unexpected error occurred in the API gateway.',
    requestId: req.requestId
  });
});

